evaluators.evaluation_logic:
const checkpoints = [];

const lots = JSON.parse(localStorage.getItem('auction_lots') || '[]');
const watchlist = JSON.parse(localStorage.getItem('watchlist_items') || '[]');

let now = new Date();
try {
  const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
  if (metadata && metadata.baselineDate) {
    // Assume 09:00Z on baseline date to approximate "today"
    now = new Date(metadata.baselineDate + 'T09:00:00Z');
  }
} catch (e) {}

const MS_PER_DAY = 1000 * 60 * 60 * 24;

function getEffectivePrice(lot) {
  if (typeof lot.current_price_amount === 'number' && !isNaN(lot.current_price_amount)) {
    return lot.current_price_amount;
  }
  return lot.starting_bid_amount;
}

const qualifyingLots = lots.filter(lot => {
  if (!lot) return false;
  if (lot.category_id !== 'bred_heifers') return false;
  if ((lot.breed || '').toLowerCase() !== 'angus') return false;
  if (lot.sex !== 'heifer') return false;
  if (lot.location_state !== 'Oklahoma') return false;
  if (lot.price_unit !== 'per_head') return false;
  const price = getEffectivePrice(lot);
  if (typeof price !== 'number' || isNaN(price) || price >= 1800) return false;
  if (!lot.closing_datetime) return false;
  const closing = new Date(lot.closing_datetime);
  if (isNaN(closing.getTime())) return false;
  const diffDays = (closing.getTime() - now.getTime()) / MS_PER_DAY;
  return diffDays >= 0 && diffDays <= 3;
});

let cheapestLot = null;
if (qualifyingLots.length > 0) {
  cheapestLot = qualifyingLots.reduce((best, lot) => {
    const priceBest = getEffectivePrice(best);
    const priceLot = getEffectivePrice(lot);
    return priceLot < priceBest ? lot : best;
  }, qualifyingLots[0]);
}

const watchlistedLotIds = watchlist.map(w => w.lot_id);
const qualifyingWatchlisted = qualifyingLots.filter(lot => watchlistedLotIds.includes(lot.id));
const cheapestWatchlisted = !!(cheapestLot && watchlistedLotIds.includes(cheapestLot.id));

// CP1 (0.6): At least one qualifying OK Angus bred heifer lot (under $1,800/head, closing in 3 days) is on the watchlist
checkpoints.push({ passed: qualifyingWatchlisted.length >= 1, weight: 0.6 });

// CP2 (0.4): The cheapest qualifying lot is on the watchlist
checkpoints.push({ passed: !!cheapestLot && cheapestWatchlisted, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lots = JSON.parse(localStorage.getItem('auction_lots') || '[]');
const bids = JSON.parse(localStorage.getItem('bids') || '[]');

function getEffectivePrice(lot) {
  if (typeof lot.current_price_amount === 'number' && !isNaN(lot.current_price_amount)) {
    return lot.current_price_amount;
  }
  return lot.starting_bid_amount;
}

const qualifyingLots = lots.filter(lot => {
  if (!lot) return false;
  if (lot.category_id !== 'feeder_cattle') return false;
  if (lot.sex !== 'steer') return false;
  if (lot.price_unit !== 'per_pound') return false;
  if (typeof lot.head_count !== 'number' || lot.head_count < 10) return false;
  // Weight between 600-800 lbs using average/min/max as in business logic
  const avg = lot.average_weight_lbs;
  const minW = lot.weight_min_lbs;
  const maxW = lot.weight_max_lbs;
  const value = (typeof avg === 'number') ? avg : (typeof minW === 'number' ? minW : maxW);
  if (typeof value !== 'number') return false;
  if (value < 600 || value > 800) return false;
  const price = getEffectivePrice(lot);
  if (typeof price !== 'number' || isNaN(price) || price > 2.20) return false;
  return true;
});

let targetLot = null;
if (qualifyingLots.length > 0) {
  targetLot = qualifyingLots.reduce((best, lot) => {
    const hBest = typeof best.head_count === 'number' ? best.head_count : 0;
    const hLot = typeof lot.head_count === 'number' ? lot.head_count : 0;
    return hLot > hBest ? lot : best;
  }, qualifyingLots[0]);
}

let hasCorrectUserBid = false;
if (targetLot) {
  const userBids = bids.filter(b => b.lot_id === targetLot.id && b.is_user_bid && b.is_maximum_bid);
  hasCorrectUserBid = userBids.some(b => {
    return typeof b.amount === 'number' && !isNaN(b.amount) &&
      b.amount === targetLot.starting_bid_amount &&
      b.price_unit === targetLot.price_unit;
  });
}

// Single CP (1.0): User has a maximum per-pound bid equal to the starting bid on the largest qualifying lot
checkpoints.push({ passed: !!targetLot && hasCorrectUserBid, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lots = JSON.parse(localStorage.getItem('auction_lots') || '[]');

let baselineDateStr = null;
try {
  const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
  if (metadata && metadata.baselineDate) {
    baselineDateStr = metadata.baselineDate;
  }
} catch (e) {}

function isClosingTenDaysFromTodayFivePM(closingIso) {
  if (!baselineDateStr || !closingIso) return false;
  const base = new Date(baselineDateStr + 'T00:00:00Z');
  if (isNaN(base.getTime())) return false;
  const expected = new Date(base.getTime());
  expected.setUTCDate(expected.getUTCDate() + 10);
  const expectedDateStr = expected.toISOString().slice(0, 10);
  const closing = new Date(closingIso);
  if (isNaN(closing.getTime())) return false;
  const closingDateStr = closing.toISOString().slice(0, 10);
  const closingTimeStr = closing.toISOString().slice(11, 16); // HH:MM
  return closingDateStr === expectedDateStr && closingTimeStr === '17:00';
}

const matchingLots = lots.filter(lot => {
  if (!lot) return false;
  if (lot.category_id !== 'bred_cows') return false;
  if ((lot.breed || '').toLowerCase() !== 'hereford') return false;
  if (lot.head_count !== 15) return false;
  if (lot.location_state !== 'Kansas') return false;
  if (lot.location_city !== 'Dodge City') return false;
  if (lot.auction_format !== 'online_timed') return false;
  if (lot.price_unit !== 'per_head') return false;
  if (!lot.is_own_listing) return false;
  if (lot.status !== 'scheduled') return false;
  if (typeof lot.starting_bid_amount !== 'number' || isNaN(lot.starting_bid_amount) || lot.starting_bid_amount <= 0) return false;
  if (typeof lot.reserve_price_amount !== 'number' || isNaN(lot.reserve_price_amount) || lot.reserve_price_amount <= 0) return false;
  if (!isClosingTenDaysFromTodayFivePM(lot.closing_datetime)) return false;
  return true;
});

// Single CP (1.0): A listing exists that satisfies all specified criteria
checkpoints.push({ passed: matchingLots.length >= 1, weight: 1.0 });

return checkPoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lots = JSON.parse(localStorage.getItem('auction_lots') || '[]');

const draftLots = lots.filter(lot => lot && lot.status === 'draft' && lot.is_own_listing);

draftLots.sort((a, b) => {
  const da = a.created_at ? new Date(a.created_at) : new Date(0);
  const db = b.created_at ? new Date(b.created_at) : new Date(0);
  return da.getTime() - db.getTime();
});

const lot = draftLots[0] || null;

const expectedNote = 'Updated lot size and pricing as of this week.';

let headOk = false;
let startingOk = false;
let closingOk = false;
let descOk = false;

if (lot) {
  headOk = lot.head_count === 18;
  startingOk = (typeof lot.starting_bid_amount === 'number' && !isNaN(lot.starting_bid_amount) && lot.starting_bid_amount === 1300);
  if (lot.closing_datetime) {
    const closing = new Date(lot.closing_datetime);
    if (!isNaN(closing.getTime())) {
      const iso = closing.toISOString();
      closingOk = iso.slice(0, 16) === '2026-03-28T21:00';
    }
  }
  descOk = typeof lot.description === 'string' && lot.description.includes(expectedNote);
}

// CP1 (0.3): Head count updated to 18 on the first draft listing
checkpoints.push({ passed: headOk, weight: 0.3 });

// CP2 (0.3): Starting bid updated to 1300 per head (an increase from original)
checkpoints.push({ passed: startingOk, weight: 0.3 });

// CP3 (0.2): Closing date moved to 2026-03-28 while keeping time at 21:00Z
checkpoints.push({ passed: closingOk, weight: 0.2 });

// CP4 (0.2): Description contains the appended note text
checkpoints.push({ passed: descOk, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const saved = JSON.parse(localStorage.getItem('saved_searches') || '[]');

const matchingSearches = saved.filter(s => {
  if (!s) return false;
  const keyword = (s.keyword || '').toLowerCase();
  const name = (s.name || '').toLowerCase();
  const hasKeyword = keyword.includes('bred heifer') || keyword.includes('bred heifers') || name.includes('bred heifers');
  const hasDescriptiveName = typeof s.name === 'string' && s.name.trim().length >= 5;
  const categoryOk = !s.category_id || s.category_id === 'bred_heifers';
  const locationOk = s.location_zip === '78701';
  const radiusOk = typeof s.radius_miles === 'number' && Math.abs(s.radius_miles - 100) <= 1; // allow small tolerance
  const priceUnitOk = !s.price_unit || s.price_unit === 'per_head';
  const priceOk = typeof s.price_max === 'number' && s.price_max <= 2000;
  const closingTypeOk = s.closing_date_filter_type === 'ending_within_days';
  const closingMaxOk = typeof s.closing_date_days_from_now_max === 'number' && s.closing_date_days_from_now_max <= 7;
  const alertsOk = s.alerts_enabled === true;
  return hasKeyword && hasDescriptiveName && categoryOk && locationOk && radiusOk && priceUnitOk && priceOk && closingTypeOk && closingMaxOk && alertsOk;
});

// Single CP (1.0): At least one saved search meets all criteria
checkpoints.push({ passed: matchingSearches.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lots = JSON.parse(localStorage.getItem('auction_lots') || '[]');
const threads = JSON.parse(localStorage.getItem('message_threads') || '[]');
const messages = JSON.parse(localStorage.getItem('messages') || '[]');

// Filter to Texas Angus bulls
let bullsTx = lots.filter(lot => {
  if (!lot) return false;
  if (lot.category_id !== 'bulls') return false;
  if (lot.location_state !== 'Texas') return false;
  if (!(lot.breed || '').toLowerCase().includes('angus')) return false;
  return true;
});

// Sort by "distance" equivalent: state then city (like searchAuctionLots distance_nearest_first)
bullsTx.sort((a, b) => {
  const sa = (a.location_state || '').localeCompare(b.location_state || '');
  if (sa !== 0) return sa;
  return (a.location_city || '').localeCompare(b.location_city || '');
});

const firstTwo = bullsTx.slice(0, 2);
let youngerLot = null;
if (firstTwo.length === 1) {
  youngerLot = firstTwo[0];
} else if (firstTwo.length === 2) {
  const age0 = typeof firstTwo[0].age_years === 'number' ? firstTwo[0].age_years : Infinity;
  const age1 = typeof firstTwo[1].age_years === 'number' ? firstTwo[1].age_years : Infinity;
  youngerLot = age0 <= age1 ? firstTwo[0] : firstTwo[1];
}

const requiredBody = "I'm interested in this Angus bull. Please confirm current weight and fertility testing status.";

let hasCorrectMessage = false;
if (youngerLot) {
  const candidateThreads = threads.filter(t => t && t.lot_id === youngerLot.id);
  for (const t of candidateThreads) {
    const msgs = messages.filter(m => m && m.thread_id === t.id && m.direction === 'outgoing');
    if (msgs.some(m => m.body === requiredBody)) {
      hasCorrectMessage = true;
      break;
    }
  }
}

// Single CP (1.0): Outgoing message with the exact required body was sent to the younger bull's seller
checkpoints.push({ passed: !!youngerLot && hasCorrectMessage, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lots = JSON.parse(localStorage.getItem('auction_lots') || '[]');
const watchlist = JSON.parse(localStorage.getItem('watchlist_items') || '[]');

let baselineDateStr = null;
try {
  const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
  if (metadata && metadata.baselineDate) {
    baselineDateStr = metadata.baselineDate;
  }
} catch (e) {}

const MS_PER_DAY = 1000 * 60 * 60 * 24;

function getEffectivePrice(lot) {
  if (typeof lot.current_price_amount === 'number' && !isNaN(lot.current_price_amount)) {
    return lot.current_price_amount;
  }
  return lot.starting_bid_amount;
}

let baseDate = null;
if (baselineDateStr) {
  baseDate = new Date(baselineDateStr + 'T00:00:00Z');
}

const qualifyingLots = lots.filter(lot => {
  if (!lot) return false;
  if (lot.category_id !== 'cow_calf_pairs') return false;
  if (lot.auction_format !== 'live_auction') return false;
  if (lot.price_unit !== 'per_pair') return false;
  const price = getEffectivePrice(lot);
  if (typeof price !== 'number' || isNaN(price) || price >= 2500) return false;
  if (!baseDate || !lot.opening_datetime) return false;
  const opening = new Date(lot.opening_datetime);
  if (isNaN(opening.getTime())) return false;
  const diffDays = (opening.getTime() - baseDate.getTime()) / MS_PER_DAY;
  return diffDays >= 14 && diffDays <= 21;
});

qualifyingLots.sort((a, b) => {
  const pa = getEffectivePrice(a);
  const pb = getEffectivePrice(b);
  if (typeof pa !== 'number') return 1;
  if (typeof pb !== 'number') return -1;
  return pa - pb;
});

const top3 = qualifyingLots.slice(0, 3);
const top3Ids = top3.map(l => l.id);
const watchIds = watchlist.map(w => w.lot_id);

const watchCount = top3Ids.filter(id => watchIds.includes(id)).length;

// CP1 (0.2): At least 1 of the 3 cheapest qualifying lots is on the watchlist
checkpoints.push({ passed: watchCount >= 1, weight: 0.2 });

// CP2 (0.3): At least 2 of the 3 cheapest qualifying lots are on the watchlist
checkpoints.push({ passed: watchCount >= 2, weight: 0.3 });

// CP3 (0.5): All 3 of the cheapest qualifying lots are on the watchlist
checkpoints.push({ passed: watchCount >= 3, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const profiles = JSON.parse(localStorage.getItem('profile_settings') || '[]');
const interests = JSON.parse(localStorage.getItem('livestock_interest_selections') || '[]');

const requiredInterests = ['feeder_cattle', 'bred_heifers', 'stocker_calves'];
const disallowedInterests = ['bred_cows', 'cow_calf_pairs', 'bulls'];

let hasContactProfile = false;
let hasFullProfile = false;

for (const p of profiles) {
  if (!p) continue;
  const contactMatch = (
    p.account_type === 'buyer' &&
    p.preferred_contact_method === 'in_site_messages_only' &&
    p.show_buying_interests_on_profile === true &&
    p.location_state === 'Nebraska' &&
    p.location_city === 'Broken Bow' &&
    typeof p.full_name === 'string' && p.full_name.trim().length > 0 &&
    typeof p.ranch_name === 'string' && p.ranch_name.trim().length > 0 &&
    typeof p.email === 'string' && p.email.trim().length > 0
  );

  if (!contactMatch) continue;

  hasContactProfile = true;

  const pInterests = interests.filter(i => i && i.profile_id === p.id && i.is_selected).map(i => i.interest_type);
  const set = new Set(pInterests);

  const requiredOk = requiredInterests.every(r => set.has(r));
  const disallowedOk = disallowedInterests.every(d => !set.has(d));

  if (requiredOk && disallowedOk) {
    hasFullProfile = true;
    break;
  }
}

// CP1 (0.4): There is a buyer profile in NE/Broken Bow with in-site messages only and buying interests visible
checkpoints.push({ passed: hasContactProfile, weight: 0.4 });

// CP2 (0.6): That profile (or one matching those contact conditions) has exactly the required interest set
checkpoints.push({ passed: hasFullProfile, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
